import FixtureList from "../components/fixture/fixture-list";
import SeasonSummary from "../components/season/season-summary";
import TigersFixtures from '../data/fixtures/fixtures'
import { fetchData } from '../services/seasonservice'
import React, { useEffect, useState } from 'react';

const Home = () => {
    const [seasons, setData] = useState(null);

    useEffect(() => {
        fetchData().then(seasons => setData(seasons));
    }, []);


    return(
        <>
            <h3>Tigers Results</h3>
            <FixtureList fixturesToShow={TigersFixtures}></FixtureList>   
            <SeasonSummary fixtures={TigersFixtures}/>
            <div>
                {seasons ? seasons.map(season => <div key={season.id}>{season.ageGroup}</div>) : "Loading..."}
            </div>
        </>
    )
}
export default Home;
